1→// Copyright (c) HashiCorp, Inc.
     2→// SPDX-License-Identifier: BUSL-1.1
     3→
     4→package jsonstate
     5→
     6→import (
     7→	"encoding/json"
     8→	"fmt"
     9→	"sort"
    10→
    11→	"github.com/zclconf/go-cty/cty"
    12→	ctyjson "github.com/zclconf/go-cty/cty/json"
    13→
    14→	"github.com/hashicorp/terraform/internal/addrs"
    15→	"github.com/hashicorp/terraform/internal/command/jsonchecks"
    16→	"github.com/hashicorp/terraform/internal/lang/marks"
    17→	"github.com/hashicorp/terraform/internal/states"
    18→	"github.com/hashicorp/terraform/internal/states/statefile"
    19→	"github.com/hashicorp/terraform/internal/terraform"
    20→)
    21→
    22→const (
    23→	// FormatVersion represents the version of the json format and will be
    24→	// incremented for any change to this format that requires changes to a
    25→	// consuming parser.
    26→	FormatVersion = "1.0"
    27→
    28→	ManagedResourceMode = "managed"
    29→	DataResourceMode    = "data"
    30→)
    31→
    32→// state is the top-level representation of the json format of a terraform
    33→// state.
    34→type state struct {
    35→	FormatVersion    string          `json:"format_version,omitempty"`
    36→	TerraformVersion string          `json:"terraform_version,omitempty"`
    37→	Values           *stateValues    `json:"values,omitempty"`
    38→	Checks           json.RawMessage `json:"checks,omitempty"`
    39→}
    40→
    41→// stateValues is the common representation of resolved values for both the prior
    42→// state (which is always complete) and the planned new state.
    43→type stateValues struct {
    44→	Outputs    map[string]Output `json:"outputs,omitempty"`
    45→	RootModule Module            `json:"root_module,omitempty"`
    46→}
    47→
    48→type Output struct {
    49→	Sensitive bool            `json:"sensitive"`
    50→	Value     json.RawMessage `json:"value,omitempty"`
    51→	Type      json.RawMessage `json:"type,omitempty"`
    52→}
    53→
    54→// Module is the representation of a module in state. This can be the root module
    55→// or a child module
    56→type Module struct {
    57→	// Resources are sorted in a user-friendly order that is undefined at this
    58→	// time, but consistent.
    59→	Resources []Resource `json:"resources,omitempty"`
    60→
    61→	// Address is the absolute module address, omitted for the root module
    62→	Address string `json:"address,omitempty"`
    63→
    64→	// Each module object can optionally have its own nested "child_modules",
    65→	// recursively describing the full module tree.
    66→	ChildModules []Module `json:"child_modules,omitempty"`
    67→}
    68→
    69→// Resource is the representation of a resource in the state.
    70→type Resource struct {
    71→	// Address is the absolute resource address
    72→	Address string `json:"address,omitempty"`
    73→
    74→	// Mode can be "managed" or "data"
    75→	Mode string `json:"mode,omitempty"`
    76→
    77→	Type string `json:"type,omitempty"`
    78→	Name string `json:"name,omitempty"`
    79→
    80→	// Index is omitted for a resource not using `count` or `for_each`.
    81→	Index json.RawMessage `json:"index,omitempty"`
    82→
    83→	// ProviderName allows the property "type" to be interpreted unambiguously
    84→	// in the unusual situation where a provider offers a resource type whose
    85→	// name does not start with its own name, such as the "googlebeta" provider
    86→	// offering "google_compute_instance".
    87→	ProviderName string `json:"provider_name"`
    88→
    89→	// SchemaVersion indicates which version of the resource type schema the
    90→	// "values" property conforms to.
    91→	SchemaVersion uint64 `json:"schema_version"`
    92→
    93→	// AttributeValues is the JSON representation of the attribute values of the
    94→	// resource, whose structure depends on the resource type schema. Any
    95→	// unknown values are omitted or set to null, making them indistinguishable
    96→	// from absent values.
    97→	AttributeValues AttributeValues `json:"values,omitempty"`
    98→
    99→	// SensitiveValues is similar to AttributeValues, but with all sensitive
   100→	// values replaced with true, and all non-sensitive leaf values omitted.
   101→	SensitiveValues json.RawMessage `json:"sensitive_values,omitempty"`
   102→
   103→	// DependsOn contains a list of the resource's dependencies. The entries are
   104→	// addresses relative to the containing module.
   105→	DependsOn []string `json:"depends_on,omitempty"`
   106→
   107→	// Tainted is true if the resource is tainted in terraform state.
   108→	Tainted bool `json:"tainted,omitempty"`
   109→
   110→	// Deposed is set if the resource is deposed in terraform state.
   111→	DeposedKey string `json:"deposed_key,omitempty"`
   112→}
   113→
   114→// AttributeValues is the JSON representation of the attribute values of the
   115→// resource, whose structure depends on the resource type schema.
   116→type AttributeValues map[string]json.RawMessage
   117→
   118→func marshalAttributeValues(value cty.Value) AttributeValues {
   119→	// unmark our value to show all values
   120→	value, _ = value.UnmarkDeep()
   121→
   122→	if value == cty.NilVal || value.IsNull() {
   123→		return nil
   124→	}
   125→
   126→	ret := make(AttributeValues)
   127→
   128→	it := value.ElementIterator()
   129→	for it.Next() {
   130→		k, v := it.Element()
   131→		vJSON, _ := ctyjson.Marshal(v, v.Type())
   132→		ret[k.AsString()] = json.RawMessage(vJSON)
   133→	}
   134→	return ret
   135→}
   136→
   137→// newState() returns a minimally-initialized state
   138→func newState() *state {
   139→	return &state{
   140→		FormatVersion: FormatVersion,
   141→	}
   142→}
   143→
   144→// MarshalForRenderer returns the pre-json encoding changes of the state, in a
   145→// format available to the structured renderer.
   146→func MarshalForRenderer(sf *statefile.File, schemas *terraform.Schemas) (Module, map[string]Output, error) {
   147→	if sf.State.Modules == nil {
   148→		// Empty state case.
   149→		return Module{}, nil, nil
   150→	}
   151→
   152→	outputs, err := MarshalOutputs(sf.State.RootOutputValues)
   153→	if err != nil {
   154→		return Module{}, nil, err
   155→	}
   156→
   157→	root, err := marshalRootModule(sf.State, schemas)
   158→	if err != nil {
   159→		return Module{}, nil, err
   160→	}
   161→
   162→	return root, outputs, err
   163→}
   164→
   165→// Marshal returns the json encoding of a terraform state.
   166→func Marshal(sf *statefile.File, schemas *terraform.Schemas) ([]byte, error) {
   167→	output := newState()
   168→
   169→	if sf == nil || sf.State.Empty() {
   170→		ret, err := json.Marshal(output)
   171→		return ret, err
   172→	}
   173→
   174→	if sf.TerraformVersion != nil {
   175→		output.TerraformVersion = sf.TerraformVersion.String()
   176→	}
   177→	// output.StateValues
   178→	err := output.marshalStateValues(sf.State, schemas)
   179→	if err != nil {
   180→		return nil, err
   181→	}
   182→	// output.Checks
   183→	if sf.State.CheckResults != nil && sf.State.CheckResults.ConfigResults.Len() > 0 {
   184→		output.Checks = jsonchecks.MarshalCheckStates(sf.State.CheckResults)
   185→	}
   186→
   187→	ret, err := json.Marshal(output)
   188→	return ret, err
   189→}
   190→
   191→func (jsonstate *state) marshalStateValues(s *states.State, schemas *terraform.Schemas) error {
   192→	var sv stateValues
   193→	var err error
   194→
   195→	// only marshal the root module outputs
   196→	sv.Outputs, err = MarshalOutputs(s.RootOutputValues)
   197→	if err != nil {
   198→		return err
   199→	}
   200→
   201→	// use the state and module map to build up the module structure
   202→	sv.RootModule, err = marshalRootModule(s, schemas)
   203→	if err != nil {
   204→		return err
   205→	}
   206→
   207→	jsonstate.Values = &sv
   208→	return nil
   209→}
   210→
   211→// MarshalOutputs translates a map of states.OutputValue to a map of jsonstate.Output,
   212→// which are defined for json encoding.
   213→func MarshalOutputs(outputs map[string]*states.OutputValue) (map[string]Output, error) {
   214→	if outputs == nil {
   215→		return nil, nil
   216→	}
   217→
   218→	ret := make(map[string]Output)
   219→	for k, v := range outputs {
   220→		ty := v.Value.Type()
   221→		ov, err := ctyjson.Marshal(v.Value, ty)
   222→		if err != nil {
   223→			return ret, err
   224→		}
   225→		ot, err := ctyjson.MarshalType(ty)
   226→		if err != nil {
   227→			return ret, err
   228→		}
   229→		ret[k] = Output{
   230→			Value:     ov,
   231→			Type:      ot,
   232→			Sensitive: v.Sensitive,
   233→		}
   234→	}
   235→
   236→	return ret, nil
   237→}
   238→
   239→func marshalRootModule(s *states.State, schemas *terraform.Schemas) (Module, error) {
   240→	var ret Module
   241→	var err error
   242→
   243→	ret.Address = ""
   244→	rs, err := marshalResources(s.RootModule().Resources, addrs.RootModuleInstance, schemas)
   245→	if err != nil {
   246→		return ret, err
   247→	}
   248→	ret.Resources = rs
   249→
   250→	// build a map of module -> set[child module addresses]
   251→	moduleChildSet := make(map[string]map[string]struct{})
   252→	for _, mod := range s.Modules {
   253→		if mod.Addr.IsRoot() {
   254→			continue
   255→		} else {
   256→			for childAddr := mod.Addr; !childAddr.IsRoot(); childAddr = childAddr.Parent() {
   257→				if _, ok := moduleChildSet[childAddr.Parent().String()]; !ok {
   258→					moduleChildSet[childAddr.Parent().String()] = map[string]struct{}{}
   259→				}
   260→				moduleChildSet[childAddr.Parent().String()][childAddr.String()] = struct{}{}
   261→			}
   262→		}
   263→	}
   264→
   265→	// transform the previous map into map of module -> [child module addresses]
   266→	moduleMap := make(map[string][]addrs.ModuleInstance)
   267→	for parent, children := range moduleChildSet {
   268→		for child := range children {
   269→			childModuleInstance, diags := addrs.ParseModuleInstanceStr(child)
   270→			if diags.HasErrors() {
   271→				return ret, diags.Err()
   272→			}
   273→			moduleMap[parent] = append(moduleMap[parent], childModuleInstance)
   274→		}
   275→	}
   276→
   277→	// use the state and module map to build up the module structure
   278→	ret.ChildModules, err = marshalModules(s, schemas, moduleMap[""], moduleMap)
   279→	return ret, err
   280→}
   281→
   282→// marshalModules is an ungainly recursive function to build a module structure
   283→// out of terraform state.
   284→func marshalModules(
   285→	s *states.State,
   286→	schemas *terraform.Schemas,
   287→	modules []addrs.ModuleInstance,
   288→	moduleMap map[string][]addrs.ModuleInstance,
   289→) ([]Module, error) {
   290→	var ret []Module
   291→	for _, child := range modules {
   292→		// cm for child module, naming things is hard.
   293→		cm := Module{Address: child.String()}
   294→
   295→		// the module may be resourceless and contain only submodules, it will then be nil here
   296→		stateMod := s.Module(child)
   297→		if stateMod != nil {
   298→			rs, err := marshalResources(stateMod.Resources, stateMod.Addr, schemas)
   299→			if err != nil {
   300→				return nil, err
   301→			}
   302→			cm.Resources = rs
   303→		}
   304→
   305→		if moduleMap[child.String()] != nil {
   306→			moreChildModules, err := marshalModules(s, schemas, moduleMap[child.String()], moduleMap)
   307→			if err != nil {
   308→				return nil, err
   309→			}
   310→			cm.ChildModules = moreChildModules
   311→		}
   312→
   313→		ret = append(ret, cm)
   314→	}
   315→
   316→	// sort the child modules by address for consistency.
   317→	sort.Slice(ret, func(i, j int) bool {
   318→		return ret[i].Address < ret[j].Address
   319→	})
   320→
   321→	return ret, nil
   322→}
   323→
   324→func marshalResources(resources map[string]*states.Resource, module addrs.ModuleInstance, schemas *terraform.Schemas) ([]Resource, error) {
   325→	var ret []Resource
   326→
   327→	var sortedResources []*states.Resource
   328→	for _, r := range resources {
   329→		sortedResources = append(sortedResources, r)
   330→	}
   331→	sort.Slice(sortedResources, func(i, j int) bool {
   332→		return sortedResources[i].Addr.Less(sortedResources[j].Addr)
   333→	})
   334→
   335→	for _, r := range sortedResources {
   336→
   337→		var sortedKeys []addrs.InstanceKey
   338→		for k := range r.Instances {
   339→			sortedKeys = append(sortedKeys, k)
   340→		}
   341→		sort.Slice(sortedKeys, func(i, j int) bool {
   342→			return addrs.InstanceKeyLess(sortedKeys[i], sortedKeys[j])
   343→		})
   344→
   345→		for _, k := range sortedKeys {
   346→			ri := r.Instances[k]
   347→
   348→			var err error
   349→
   350→			resAddr := r.Addr.Resource
   351→
   352→			current := Resource{
   353→				Address:      r.Addr.Instance(k).String(),
   354→				Type:         resAddr.Type,
   355→				Name:         resAddr.Name,
   356→				ProviderName: r.ProviderConfig.Provider.String(),
   357→			}
   358→
   359→			if k != nil {
   360→				index := k.Value()
   361→				if current.Index, err = ctyjson.Marshal(index, index.Type()); err != nil {
   362→					return nil, err
   363→				}
   364→			}
   365→
   366→			switch resAddr.Mode {
   367→			case addrs.ManagedResourceMode:
   368→				current.Mode = ManagedResourceMode
   369→			case addrs.DataResourceMode:
   370→				current.Mode = DataResourceMode
   371→			default:
   372→				return ret, fmt.Errorf("resource %s has an unsupported mode %s",
   373→					resAddr.String(),
   374→					resAddr.Mode.String(),
   375→				)
   376→			}
   377→
   378→			schema, version := schemas.ResourceTypeConfig(
   379→				r.ProviderConfig.Provider,
   380→				resAddr.Mode,
   381→				resAddr.Type,
   382→			)
   383→
   384→			// It is possible that the only instance is deposed
   385→			if ri.Current != nil {
   386→				if version != ri.Current.SchemaVersion {
   387→					return nil, fmt.Errorf("schema version %d for %s in state does not match version %d from the provider", ri.Current.SchemaVersion, resAddr, version)
   388→				}
   389→
   390→				current.SchemaVersion = ri.Current.SchemaVersion
   391→
   392→				if schema == nil {
   393→					return nil, fmt.Errorf("no schema found for %s (in provider %s)", resAddr.String(), r.ProviderConfig.Provider)
   394→				}
   395→				riObj, err := ri.Current.Decode(schema.ImpliedType())
   396→				if err != nil {
   397→					return nil, err
   398→				}
   399→
   400→				current.AttributeValues = marshalAttributeValues(riObj.Value)
   401→
   402→				value, marks := riObj.Value.UnmarkDeepWithPaths()
   403→				if schema.ContainsSensitive() {
   404→					marks = append(marks, schema.ValueMarks(value, nil)...)
   405→				}
   406→				s := SensitiveAsBool(value.MarkWithPaths(marks))
   407→				v, err := ctyjson.Marshal(s, s.Type())
   408→				if err != nil {
   409→					return nil, err
   410→				}
   411→				current.SensitiveValues = v
   412→
   413→				if len(riObj.Dependencies) > 0 {
   414→					dependencies := make([]string, len(riObj.Dependencies))
   415→					for i, v := range riObj.Dependencies {
   416→						dependencies[i] = v.String()
   417→					}
   418→					current.DependsOn = dependencies
   419→				}
   420→
   421→				if riObj.Status == states.ObjectTainted {
   422→					current.Tainted = true
   423→				}
   424→				ret = append(ret, current)
   425→			}
   426→
   427→			var sortedDeposedKeys []string
   428→			for k := range ri.Deposed {
   429→				sortedDeposedKeys = append(sortedDeposedKeys, string(k))
   430→			}
   431→			sort.Strings(sortedDeposedKeys)
   432→
   433→			for _, deposedKey := range sortedDeposedKeys {
   434→				rios := ri.Deposed[states.DeposedKey(deposedKey)]
   435→
   436→				// copy the base fields from the current instance
   437→				deposed := Resource{
   438→					Address:      current.Address,
   439→					Type:         current.Type,
   440→					Name:         current.Name,
   441→					ProviderName: current.ProviderName,
   442→					Mode:         current.Mode,
   443→					Index:        current.Index,
   444→				}
   445→
   446→				riObj, err := rios.Decode(schema.ImpliedType())
   447→				if err != nil {
   448→					return nil, err
   449→				}
   450→
   451→				deposed.AttributeValues = marshalAttributeValues(riObj.Value)
   452→
   453→				value, marks := riObj.Value.UnmarkDeepWithPaths()
   454→				if schema.ContainsSensitive() {
   455→					marks = append(marks, schema.ValueMarks(value, nil)...)
   456→				}
   457→				s := SensitiveAsBool(value.MarkWithPaths(marks))
   458→				v, err := ctyjson.Marshal(s, s.Type())
   459→				if err != nil {
   460→					return nil, err
   461→				}
   462→				deposed.SensitiveValues = v
   463→
   464→				if len(riObj.Dependencies) > 0 {
   465→					dependencies := make([]string, len(riObj.Dependencies))
   466→					for i, v := range riObj.Dependencies {
   467→						dependencies[i] = v.String()
   468→					}
   469→					deposed.DependsOn = dependencies
   470→				}
   471→
   472→				if riObj.Status == states.ObjectTainted {
   473→					deposed.Tainted = true
   474→				}
   475→				deposed.DeposedKey = deposedKey
   476→				ret = append(ret, deposed)
   477→			}
   478→		}
   479→	}
   480→
   481→	return ret, nil
   482→}
   483→
   484→func SensitiveAsBool(val cty.Value) cty.Value {
   485→	if val.HasMark(marks.Sensitive) {
   486→		return cty.True
   487→	}
   488→
   489→	ty := val.Type()
   490→	switch {
   491→	case val.IsNull(), ty.IsPrimitiveType(), ty.Equals(cty.DynamicPseudoType):
   492→		return cty.False
   493→	case ty.IsListType() || ty.IsTupleType() || ty.IsSetType():
   494→		if !val.IsKnown() {
   495→			// If the collection is unknown we can't say anything about the
   496→			// sensitivity of its contents
   497→			return cty.EmptyTupleVal
   498→		}
   499→		length := val.LengthInt()
   500→		if length == 0 {
   501→			// If there are no elements then we can't have sensitive values
   502→			return cty.EmptyTupleVal
   503→		}
