   212→// which are defined for json encoding.
   213→func MarshalOutputs(outputs map[string]*states.OutputValue) (map[string]Output, error) {
   214→	if outputs == nil {
   215→		return nil, nil
   216→	}
   217→
   218→	ret := make(map[string]Output)
   219→	for k, v := range outputs {
   220→		ty := v.Value.Type()
   221→		ov, err := ctyjson.Marshal(v.Value, ty)
   222→		if err != nil {
   223→			return ret, err
   224→		}
   225→		ot, err := ctyjson.MarshalType(ty)
   226→		if err != nil {
   227→			return ret, err
   228→		}
   229→		ret[k] = Output{
   230→			Value:     ov,
   231→			Type:      ot,
   232→			Sensitive: v.Sensitive,
   233→		}
   234→	}
   235→
   236→	return ret, nil
   237→}
   238→
   239→func marshalRootModule(s *states.State, schemas *terraform.Schemas) (Module, error) {
   240→	var ret Module
   241→	var err error
   242→
   243→	ret.Address = ""
   244→	rs, err := marshalResources(s.RootModule().Resources, addrs.RootModuleInstance, schemas)
   245→	if err != nil {
   246→		return ret, err
   247→	}
   248→	ret.Resources = rs
   249→
   250→	// build a map of module -> set[child module addresses]
   251→	moduleChildSet := make(map[string]map[string]struct{})
   252→	for _, mod := range s.Modules {
   253→		if mod.Addr.IsRoot() {
   254→			continue
   255→		} else {
   256→			for childAddr := mod.Addr; !childAddr.IsRoot(); childAddr = childAddr.Parent() {
   257→				if _, ok := moduleChildSet[childAddr.Parent().String()]; !ok {
   258→					moduleChildSet[childAddr.Parent().String()] = map[string]struct{}{}
   259→				}
   260→				moduleChildSet[childAddr.Parent().String()][childAddr.String()] = struct{}{}
   261→			}
   262→		}
   263→	}
   264→
   265→	// transform the previous map into map of module -> [child module addresses]
   266→	moduleMap := make(map[string][]addrs.ModuleInstance)
   267→	for parent, children := range moduleChildSet {
   268→		for child := range children {
   269→			childModuleInstance, diags := addrs.ParseModuleInstanceStr(child)
   270→			if diags.HasErrors() {
   271→				return ret, diags.Err()
   272→			}
   273→			moduleMap[parent] = append(moduleMap[parent], childModuleInstance)
   274→		}
   275→	}
   276→
   277→	// use the state and module map to build up the module structure
   278→	ret.ChildModules, err = marshalModules(s, schemas, moduleMap[""], moduleMap)
   279→	return ret, err
   280→}
   281→
   282→// marshalModules is an ungainly recursive function to build a module structure
   283→// out of terraform state.
   284→func marshalModules(
   285→	s *states.State,
   286→	schemas *terraform.Schemas,
   287→	modules []addrs.ModuleInstance,
   288→	moduleMap map[string][]addrs.ModuleInstance,
   289→) ([]Module, error) {
   290→	var ret []Module
   291→	for _, child := range modules {
   292→		// cm for child module, naming things is hard.
   293→		cm := Module{Address: child.String()}
   294→
   295→		// the module may be resourceless and contain only submodules, it will then be nil here
   296→		stateMod := s.Module(child)
   297→		if stateMod != nil {
   298→			rs, err := marshalResources(stateMod.Resources, stateMod.Addr, schemas)
   299→			if err != nil {
   300→				return nil, err
   301→			}
   302→			cm.Resources = rs
   303→		}
   304→
   305→		if moduleMap[child.String()] != nil {
   306→			moreChildModules, err := marshalModules(s, schemas, moduleMap[child.String()], moduleMap)
   307→			if err != nil {
   308→				return nil, err
   309→			}
   310→			cm.ChildModules = moreChildModules
   311→		}
   312→
   313→		ret = append(ret, cm)
   314→	}
   315→
   316→	// sort the child modules by address for consistency.
   317→	sort.Slice(ret, func(i, j int) bool {
   318→		return ret[i].Address < ret[j].Address
   319→	})
   320→
   321→	return ret, nil
   322→}
   323→
   324→func marshalResources(resources map[string]*states.Resource, module addrs.ModuleInstance, schemas *terraform.Schemas) ([]Resource, error) {
   325→	var ret []Resource
   326→
   327→	var sortedResources []*states.Resource
   328→	for _, r := range resources {
   329→		sortedResources = append(sortedResources, r)
   330→	}
   331→	sort.Slice(sortedResources, func(i, j int) bool {
   332→		return sortedResources[i].Addr.Less(sortedResources[j].Addr)
   333→	})
   334→
   335→	for _, r := range sortedResources {
   336→
   337→		var sortedKeys []addrs.InstanceKey
   338→		for k := range r.Instances {
   339→			sortedKeys = append(sortedKeys, k)
   340→		}
   341→		sort.Slice(sortedKeys, func(i, j int) bool {
   342→			return addrs.InstanceKeyLess(sortedKeys[i], sortedKeys[j])
   343→		})
   344→
   345→		for _, k := range sortedKeys {
   346→			ri := r.Instances[k]
   347→
   348→			var err error
   349→
   350→			resAddr := r.Addr.Resource
   351→
   352→			current := Resource{
   353→				Address:      r.Addr.Instance(k).String(),
   354→				Type:         resAddr.Type,
   355→				Name:         resAddr.Name,
   356→				ProviderName: r.ProviderConfig.Provider.String(),
   357→			}
   358→
   359→			if k != nil {
   360→				index := k.Value()
   361→				if current.Index, err = ctyjson.Marshal(index, index.Type()); err != nil {
   362→					return nil, err
   363→				}
   364→			}
   365→
   366→			switch resAddr.Mode {
   367→			case addrs.ManagedResourceMode:
   368→				current.Mode = ManagedResourceMode
   369→			case addrs.DataResourceMode:
   370→				current.Mode = DataResourceMode
   371→			default:
   372→				return ret, fmt.Errorf("resource %s has an unsupported mode %s",
   373→					resAddr.String(),
   374→					resAddr.Mode.String(),
   375→				)
   376→			}
   377→
   378→			schema, version := schemas.ResourceTypeConfig(
   379→				r.ProviderConfig.Provider,
   380→				resAddr.Mode,
   381→				resAddr.Type,
   382→			)
   383→
   384→			// It is possible that the only instance is deposed
   385→			if ri.Current != nil {
   386→				if version != ri.Current.SchemaVersion {
   387→					return nil, fmt.Errorf("schema version %d for %s in state does not match version %d from the provider", ri.Current.SchemaVersion, resAddr, version)
   388→				}
   389→
   390→				current.SchemaVersion = ri.Current.SchemaVersion
   391→
   392→				if schema == nil {
   393→					return nil, fmt.Errorf("no schema found for %s (in provider %s)", resAddr.String(), r.ProviderConfig.Provider)
   394→				}
   395→				riObj, err := ri.Current.Decode(schema.ImpliedType())
   396→				if err != nil {
   397→					return nil, err
   398→				}
   399→
   400→				current.AttributeValues = marshalAttributeValues(riObj.Value)
   401→
   402→				value, marks := riObj.Value.UnmarkDeepWithPaths()
   403→				if schema.ContainsSensitive() {
   404→					marks = append(marks, schema.ValueMarks(value, nil)...)
   405→				}
   406→				s := SensitiveAsBool(value.MarkWithPaths(marks))
   407→				v, err := ctyjson.Marshal(s, s.Type())
   408→				if err != nil {
   409→					return nil, err
   410→				}
   411→				current.SensitiveValues = v
   412→
   413→				if len(riObj.Dependencies) > 0 {
   414→					dependencies := make([]string, len(riObj.Dependencies))
   415→					for i, v := range riObj.Dependencies {
   416→						dependencies[i] = v.String()
   417→					}
   418→					current.DependsOn = dependencies
   419→				}
   420→
   421→				if riObj.Status == states.ObjectTainted {
   422→					current.Tainted = true
   423→				}
   424→				ret = append(ret, current)
   425→			}
   426→
   427→			var sortedDeposedKeys []string
   428→			for k := range ri.Deposed {
   429→				sortedDeposedKeys = append(sortedDeposedKeys, string(k))
   430→			}
   431→			sort.Strings(sortedDeposedKeys)
   432→
   433→			for _, deposedKey := range sortedDeposedKeys {
   434→				rios := ri.Deposed[states.DeposedKey(deposedKey)]
   435→
   436→				// copy the base fields from the current instance
   437→				deposed := Resource{
   438→					Address:      current.Address,
   439→					Type:         current.Type,
   440→					Name:         current.Name,
   441→					ProviderName: current.ProviderName,
   442→					Mode:         current.Mode,
   443→					Index:        current.Index,
   444→				}
   445→
   446→				riObj, err := rios.Decode(schema.ImpliedType())
   447→				if err != nil {
   448→					return nil, err
   449→				}
   450→
   451→				deposed.AttributeValues = marshalAttributeValues(riObj.Value)
   452→
   453→				value, marks := riObj.Value.UnmarkDeepWithPaths()
   454→				if schema.ContainsSensitive() {
   455→					marks = append(marks, schema.ValueMarks(value, nil)...)
   456→				}
   457→				s := SensitiveAsBool(value.MarkWithPaths(marks))
   458→				v, err := ctyjson.Marshal(s, s.Type())
   459→				if err != nil {
   460→					return nil, err
   461→				}
   462→				deposed.SensitiveValues = v
   463→
   464→				if len(riObj.Dependencies) > 0 {
   465→					dependencies := make([]string, len(riObj.Dependencies))
   466→					for i, v := range riObj.Dependencies {
   467→						dependencies[i] = v.String()
   468→					}
   469→					deposed.DependsOn = dependencies
   470→				}
   471→
   472→				if riObj.Status == states.ObjectTainted {
   473→					deposed.Tainted = true
   474→				}
   475→				deposed.DeposedKey = deposedKey
   476→				ret = append(ret, deposed)
   477→			}
   478→		}
   479→	}
   480→
   481→	return ret, nil
   482→}
   483→
   484→func SensitiveAsBool(val cty.Value) cty.Value {
   485→	if val.HasMark(marks.Sensitive) {
   486→		return cty.True
   487→	}
   488→
   489→	ty := val.Type()
   490→	switch {
   491→	case val.IsNull(), ty.IsPrimitiveType(), ty.Equals(cty.DynamicPseudoType):
   492→		return cty.False
   493→	case ty.IsListType() || ty.IsTupleType() || ty.IsSetType():
   494→		if !val.IsKnown() {
   495→			// If the collection is unknown we can't say anything about the
   496→			// sensitivity of its contents
   497→			return cty.EmptyTupleVal
   498→		}
   499→		length := val.LengthInt()
   500→		if length == 0 {
   501→			// If there are no elements then we can't have sensitive values
   502→			return cty.EmptyTupleVal
   503→		}
   504→		vals := make([]cty.Value, 0, length)
   505→		it := val.ElementIterator()
   506→		for it.Next() {
   507→			_, v := it.Element()
   508→			vals = append(vals, SensitiveAsBool(v))
   509→		}
   510→		// The above transform may have changed the types of some of the
   511→		// elements, so we'll always use a tuple here in case we've now made
   512→		// different elements have different types. Our ultimate goal is to
   513→		// marshal to JSON anyway, and all of these sequence types are
   514→		// indistinguishable in JSON.
   515→		return cty.TupleVal(vals)
   516→	case ty.IsMapType() || ty.IsObjectType():
   517→		if !val.IsKnown() {
   518→			// If the map/object is unknown we can't say anything about the
   519→			// sensitivity of its attributes
   520→			return cty.EmptyObjectVal
   521→		}
   522→		var length int
   523→		switch {
   524→		case ty.IsMapType():
   525→			length = val.LengthInt()
   526→		default:
   527→			length = len(val.Type().AttributeTypes())
   528→		}
   529→		if length == 0 {
   530→			// If there are no elements then we can't have sensitive values
   531→			return cty.EmptyObjectVal
   532→		}
   533→		vals := make(map[string]cty.Value)
   534→		it := val.ElementIterator()
   535→		for it.Next() {
   536→			k, v := it.Element()
   537→			s := SensitiveAsBool(v)
   538→			// Omit all of the "false"s for non-sensitive values for more
   539→			// compact serialization
   540→			if !s.RawEquals(cty.False) {
   541→				vals[k.AsString()] = s
   542→			}
   543→		}
   544→		// The above transform may have changed the types of some of the
   545→		// elements, so we'll always use an object here in case we've now made
   546→		// different elements have different types. Our ultimate goal is to
   547→		// marshal to JSON anyway, and all of these mapping types are
   548→		// indistinguishable in JSON.
   549→		return cty.ObjectVal(vals)
   550→	default:
   551→		// Should never happen, since the above should cover all types
   552→		panic(fmt.Sprintf("sensitiveAsBool cannot handle %#v", val))
   553→	}
   554→}
   555→

