   211→// MarshalOutputs translates a map of states.OutputValue to a map of jsonstate.Output,
   212→// which are defined for json encoding.
   213→func MarshalOutputs(outputs map[string]*states.OutputValue) (map[string]Output, error) {
   214→	if outputs == nil {
   215→		return nil, nil
   216→	}
   217→
   218→	ret := make(map[string]Output)
   219→	for k, v := range outputs {
   220→		ty := v.Value.Type()
   221→		ov, err := ctyjson.Marshal(v.Value, ty)
   222→		if err != nil {
   223→			return ret, err
   224→		}
   225→		ot, err := ctyjson.MarshalType(ty)
   226→		if err != nil {
