   239→func marshalRootModule(s *states.State, schemas *terraform.Schemas) (Module, error) {
   240→	var ret Module
   241→	var err error
   242→
   243→	ret.Address = ""
   244→	rs, err := marshalResources(s.RootModule().Resources, addrs.RootModuleInstance, schemas)
   245→	if err != nil {
