   248→	ret.Resources = rs
   249→
   250→	// build a map of module -> set[child module addresses]
   251→	moduleChildSet := make(map[string]map[string]struct{})
   252→	for _, mod := range s.Modules {
   253→		if mod.Addr.IsRoot() {
   254→			continue
   255→		} else {
   256→			for childAddr := mod.Addr; !childAddr.IsRoot(); childAddr = childAddr.Parent() {
   257→				if _, ok := moduleChildSet[childAddr.Parent().String()]; !ok {
   258→					moduleChildSet[childAddr.Parent().String()] = map[string]struct{}{}
   259→				}
   260→				moduleChildSet[childAddr.Parent().String()][childAddr.String()] = struct{}{}
   261→			}
   262→		}
   263→	}
   264→
   265→	// transform the previous map into map of module -> [child module addresses]
   266→	moduleMap := make(map[string][]addrs.ModuleInstance)
   267→	for parent, children := range moduleChildSet {
   268→		for child := range children {
