   436→				// copy the base fields from the current instance
   437→				deposed := Resource{
   438→					Address:      current.Address,
   439→					Type:         current.Type,
   440→					Name:         current.Name,
   441→					ProviderName: current.ProviderName,
   442→					Mode:         current.Mode,
   443→					Index:        current.Index,
   444→				}
   445→
   446→				riObj, err := rios.Decode(schema.ImpliedType())
   447→				if err != nil {
   448→					return nil, err
   449→				}
   450→
   451→				deposed.AttributeValues = marshalAttributeValues(riObj.Value)
   452→
   453→				value, marks := riObj.Value.UnmarkDeepWithPaths()
   454→				if schema.ContainsSensitive() {
   455→					marks = append(marks, schema.ValueMarks(value, nil)...)
   456→				}
   457→				s := SensitiveAsBool(value.MarkWithPaths(marks))
   458→				v, err := ctyjson.Marshal(s, s.Type())
   459→				if err != nil {
   460→					return nil, err
   461→				}
   462→				deposed.SensitiveValues = v
   463→
