   523→		switch {
   524→		case ty.IsMapType():
   525→			length = val.LengthInt()
   526→		default:
   527→			length = len(val.Type().AttributeTypes())
   528→		}
   529→		if length == 0 {
   530→			// If there are no elements then we can't have sensitive values
   531→			return cty.EmptyObjectVal
   532→		}
   533→		vals := make(map[string]cty.Value)
   534→		it := val.ElementIterator()
   535→		for it.Next() {
   536→			k, v := it.Element()
   537→			s := SensitiveAsBool(v)
